128	 this function initializes the given stream, it allocates the respective memory if necessary (stream=0)
129	  and sets all the respective values to zero.
130	 input:   - steam to be initialized (or zero if memory shall be allocated)
131	 output:  - the same stream
132	 */
133	tarmaStream_t *tarmaInitStream(tarmaStream_t *stream)
134	{
135	  if(stream==0) {
136	    stream=(tarmaStream_t*) malloc(sizeof(tarmaStream_t));
137	  }
138	
139	  tarmaProcess_t *proc;
140	  int cntvar, cntp, cntma, cntar, cntpy;
141	
142	  for(cntvar=0; cntvar<2; cntvar++) {
143	    if(cntvar==0) {
144	      proc=&(stream->tarma_idt);
145	    } else {
146	      proc=&(stream->tarma_size);
147	    }
148	
149	    for(cntp=0; cntp<TARMA_NUM_PROCESSES; cntp++) {
150	      proc->inputWeight[cntp]=0;
151	    }
152	
153	    for(cntma=0; cntma<TARMA_NUM_MA_MAX; cntma++) {
154	      proc->maWeight[cntma]=0;
155	      proc->maHist[cntma]=0;
156	    }
157	
158	    for(cntar=0; cntar<TARMA_NUM_AR_MAX; cntar++) {
159	      proc->arWeight[cntar]=0;
160	      proc->arHist[cntar]=0;
161	    }
162	
163	    for(cntpy=0; cntpy<TARMA_NUM_POLY_MAX; cntpy++) {
164	      proc->polyWeight[cntpy]=0;
165	    }
166	  }
167	
168	  LOG_D(OTG,"TARMA_DEBUG: tarmaInitStream(%p) called\n", stream);
169	  return stream;
170	}
